#include <bits/stdc++.h>
using namespace std;

int main() {
    string s;
    cin >> s;

    if (s.length() == 0) {
        cout << 0 << endl;
        return 0;
    }

    vector<int> charCount(128, 0);
    int left = 0;
    int maxLength = 0;

    for (int right = 0; right < s.length(); ++right) {
        charCount[s[right]]++;

        while (charCount[s[right]] > 1) {
            charCount[s[left]]--;
            left++;
        }

        maxLength = max(maxLength, right - left + 1);
    }

    cout << maxLength << endl;

    return 0;
}

