#include <stdio.h>
#include <string.h>

int main() {
    char s[1000001];
    scanf("%s", s);

    if (strlen(s) == 0) {
        printf("0\n");
        return 0;
    }

    int charCount[128] = {0};
    int left = 0;
    int maxLength = 0;

    for (int right = 0; s[right] != '\0'; right++) {
        charCount[(int)s[right]]++;

        while (charCount[(int)s[right]] > 1) {
            charCount[(int)s[left]]--;
            left++;
        }

        if (right - left + 1 > maxLength) {
            maxLength = right - left + 1;
        }
    }

    printf("%d\n", maxLength);
    return 0;
}

